package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintReturnsCSVPrinter() throws IOException {
        Appendable appendable = new StringBuilder();
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);
        assertEquals(appendable, printer.getOut());
    }

    @Test
    void testPrintWithMockAppendable() throws IOException {
        Appendable appendable = mock(Appendable.class);
        // Mock append(CharSequence) to do nothing to avoid IOException during CSVPrinter construction
        doNothing().when(appendable).append(any(CharSequence.class));
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);
        assertEquals(appendable, printer.getOut());
    }

    @Test
    void testPrintThrowsIOException() throws Exception {
        Appendable appendable = mock(Appendable.class);
        doThrow(new IOException("test exception")).when(appendable).append(any(CharSequence.class));

        IOException thrown = assertThrows(IOException.class, () -> {
            csvFormat.print(appendable);
        });

        assertEquals("test exception", thrown.getMessage());
    }
}
